CREATE TABLE skill_category (id uuid NOT NULL,category_key varchar(100) NOT NULL,sort_order integer NOT NULL,is_active boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_skill_category PRIMARY KEY(id),CONSTRAINT uq_skill_category_key UNIQUE(category_key),CONSTRAINT ck_skill_category_key CHECK(btrim(category_key)<>''),CONSTRAINT ck_skill_category_order CHECK(sort_order>=0),CONSTRAINT fk_skill_category_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_skill_category_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_skill_category_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL);
CREATE INDEX ix_skill_category_active_order ON skill_category(is_active,sort_order,id);
CREATE TABLE skill_category_translation (id uuid NOT NULL,skill_category_id uuid NOT NULL,language_code varchar(2) NOT NULL,name varchar(255) NOT NULL,description text NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_skill_category_translation PRIMARY KEY(id),CONSTRAINT uq_skill_category_translation_locale UNIQUE(skill_category_id,language_code),CONSTRAINT ck_skill_category_translation_locale CHECK(language_code IN('fa','en')),CONSTRAINT ck_skill_category_translation_name CHECK(btrim(name)<>''),CONSTRAINT fk_skill_category_translation_category FOREIGN KEY(skill_category_id) REFERENCES skill_category(id) ON DELETE CASCADE,CONSTRAINT fk_skill_category_translation_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_skill_category_translation_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_skill_category_translation_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL);
CREATE TABLE skill (id uuid NOT NULL,skill_key varchar(100) NOT NULL,skill_category_id uuid NOT NULL,sort_order integer NOT NULL,is_active boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_skill PRIMARY KEY(id),CONSTRAINT uq_skill_key UNIQUE(skill_key),CONSTRAINT ck_skill_key CHECK(btrim(skill_key)<>''),CONSTRAINT ck_skill_order CHECK(sort_order>=0),CONSTRAINT fk_skill_category FOREIGN KEY(skill_category_id) REFERENCES skill_category(id) ON DELETE RESTRICT,CONSTRAINT fk_skill_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_skill_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_skill_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL);
CREATE INDEX ix_skill_category_id_active_order ON skill(skill_category_id,is_active,sort_order,id);
CREATE TABLE skill_translation (id uuid NOT NULL,skill_id uuid NOT NULL,language_code varchar(2) NOT NULL,name varchar(255) NOT NULL,description text NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_skill_translation PRIMARY KEY(id),CONSTRAINT uq_skill_translation_locale UNIQUE(skill_id,language_code),CONSTRAINT ck_skill_translation_locale CHECK(language_code IN('fa','en')),CONSTRAINT ck_skill_translation_name CHECK(btrim(name)<>''),CONSTRAINT fk_skill_translation_skill FOREIGN KEY(skill_id) REFERENCES skill(id) ON DELETE CASCADE,CONSTRAINT fk_skill_translation_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_skill_translation_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_skill_translation_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL);
CREATE TABLE portfolio_project (id uuid NOT NULL,project_key varchar(100) NOT NULL,cover_media_id uuid NULL,status varchar(20) NOT NULL,started_on date NULL,ended_on date NULL,project_url varchar(2048) NULL,repository_url varchar(2048) NULL,sort_order integer NOT NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_portfolio_project PRIMARY KEY(id),CONSTRAINT uq_portfolio_project_key UNIQUE(project_key),CONSTRAINT ck_portfolio_project_key CHECK(btrim(project_key)<>''),CONSTRAINT ck_portfolio_project_status CHECK(status IN('DRAFT','PUBLISHED','ARCHIVED')),CONSTRAINT ck_portfolio_project_publish CHECK(status<>'PUBLISHED' OR started_on IS NOT NULL),CONSTRAINT ck_portfolio_project_dates CHECK(ended_on IS NULL OR started_on IS NULL OR ended_on>=started_on),CONSTRAINT ck_portfolio_project_order CHECK(sort_order>=0),CONSTRAINT fk_portfolio_project_media FOREIGN KEY(cover_media_id) REFERENCES media_asset(id) ON DELETE RESTRICT,CONSTRAINT fk_portfolio_project_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_portfolio_project_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_portfolio_project_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL);
CREATE INDEX ix_portfolio_project_status_order ON portfolio_project(status,sort_order,id);
CREATE TABLE portfolio_project_translation (id uuid NOT NULL,portfolio_project_id uuid NOT NULL,language_code varchar(2) NOT NULL,title varchar(255) NOT NULL,slug varchar(255) NOT NULL,summary text NULL,body_markdown text NULL,seo_title varchar(255) NULL,seo_description varchar(500) NULL,created_at timestamptz NOT NULL,updated_at timestamptz NOT NULL,created_by uuid NULL,updated_by uuid NULL,deleted_at timestamptz NULL,deleted_by uuid NULL,version bigint NOT NULL DEFAULT 0,CONSTRAINT pk_portfolio_project_translation PRIMARY KEY(id),CONSTRAINT uq_portfolio_project_translation_locale UNIQUE(portfolio_project_id,language_code),CONSTRAINT ck_portfolio_project_translation_locale CHECK(language_code IN('fa','en')),CONSTRAINT ck_portfolio_project_translation_title CHECK(btrim(title)<>''),CONSTRAINT ck_portfolio_project_translation_slug CHECK(btrim(slug)<>''),CONSTRAINT fk_portfolio_project_translation_project FOREIGN KEY(portfolio_project_id) REFERENCES portfolio_project(id) ON DELETE CASCADE,CONSTRAINT fk_portfolio_project_translation_created_by FOREIGN KEY(created_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_portfolio_project_translation_updated_by FOREIGN KEY(updated_by) REFERENCES app_user(id) ON DELETE SET NULL,CONSTRAINT fk_portfolio_project_translation_deleted_by FOREIGN KEY(deleted_by) REFERENCES app_user(id) ON DELETE SET NULL);
CREATE UNIQUE INDEX ux_portfolio_project_translation_slug ON portfolio_project_translation(language_code,lower(slug)) WHERE deleted_at IS NULL;
CREATE TABLE portfolio_project_skill (portfolio_project_id uuid NOT NULL,skill_id uuid NOT NULL,sort_order integer NOT NULL,CONSTRAINT pk_portfolio_project_skill PRIMARY KEY(portfolio_project_id,skill_id),CONSTRAINT uq_portfolio_project_skill_order UNIQUE(portfolio_project_id,sort_order),CONSTRAINT ck_portfolio_project_skill_order CHECK(sort_order>=0),CONSTRAINT fk_portfolio_project_skill_project FOREIGN KEY(portfolio_project_id) REFERENCES portfolio_project(id) ON DELETE CASCADE,CONSTRAINT fk_portfolio_project_skill_skill FOREIGN KEY(skill_id) REFERENCES skill(id) ON DELETE RESTRICT);
CREATE INDEX ix_portfolio_project_skill_reverse ON portfolio_project_skill(skill_id,portfolio_project_id);
